import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionVulnerable {

    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

            System.out.print("Enter the directory name to list files: ");
            String directory = reader.readLine();

            // Vulnerability: User input is directly passed to execute shell command
            String command = "ls " + directory;

            Process process = Runtime.getRuntime().exec(command);

            BufferedReader outputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;

            System.out.println("Listing files in directory: " + directory);
            while ((line = outputReader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

